const data = [];

inline function add(arr: Array)
{
	data.concat(arr);
}

inline function process()
{
	local stack = data.clone();

	while (stack.length > 0)
	{
		//local node = stack.shift();
		local node = stack.pop();

		if (!isDefined(node.type) || !isDefined(node.id))
			continue;

		addComponent(node.id, node);

		if (!isDefined(node.childComponents))
			continue;

		for (x in node.childComponents)
			x.parentComponent = node.id;

		for (i = node.childComponents.length - 1; i >= 0; i--)
			stack.push(node.childComponents[i]);

		//stack.concat(node.childComponents);
	}
}

inline function:
object addComponent(id: string, properties: JSON)
{
	local c = Content.getComponent(id);

	if (!isDefined(c))
	{
		local type = properties.type.replace("Scripted").replace("Script");

		switch (type)
		{
		case "Slider":
			c = Content.addKnob(id, properties.x, properties.y);
			break;

		case "Button":
			c = Content.addButton(id, properties.x, properties.y);
			break;

		case "Table":
			c = Content.addTable(id, properties.x, properties.y);
			break;

		case "ComboBox":
			c = Content.addComboBox(id, properties.x, properties.y);
			break;

		case "Label":
			c = Content.addLabel(id, properties.x, properties.y);
			break;

		case "Image":
			c = Content.addImage(id, properties.x, properties.y);
			break;

		case "Viewport":
			c = Content.addViewport(id, properties.x, properties.y);
			break;

		case "Panel":
			c = Content.addPanel(id, properties.x, properties.y);
			break;

		case "AudioWaveform":
			c = Content.addAudioWaveform(id, properties.x, properties.y);
			break;

		case "SliderPack":
			c = Content.addSliderPack(id, properties.x, properties.y);
			break;

		case "WebView":
			c = Content.addWebView(id, properties.x, properties.y);
			break;

		case "FloatingTile":
			c = Content.addFloatingTile(id, properties.x, properties.y);
			break;
		}
	}

	local allProperties = c.getAllProperties();

	for (x in properties)
	{
		if (!allProperties.contains(x) || ["id"].contains(x))
			continue;

		c.set(x, properties[x]);
	}

	return c;
}
}

