// Keep the mouse position
var MOUSE_POS = [0, 0];

// This function will be called whenever the mouse is hovered over a component
// it stores the (global) mouse position and hides the panel if the mouse exits
// any component
TooltipWatcher.addListener(TooltipPanel, "hide tooltip", function(component, event)
{
	MOUSE_POS = [component.getGlobalPositionX() + event.x,
	             component.getGlobalPositionY() + event.y];

	if(!event.hover)
		this.set("visible", false);
});

// This function will be called after half a second and shows and repositions the
// tooltip when the mouse position hasn't changed much in the last time
TooltipWatcher.addDelayedListener(500, TooltipPanel, "show tooltip", function(component, event)
{
	// if this is true for the last callback, we don't want to show the tooltip
	if(!event.hover)
		return;

	var pos = [component.getGlobalPositionX() + event.x,
	           component.getGlobalPositionY() + event.y];

	if(Math.abs(MOUSE_POS[0] - pos[0]) < 10 &&
	        Math.abs(MOUSE_POS[0] - pos[0]) < 10)
	{
		this.set("visible", true);
		this.set("x", pos[0] + 10);
		this.set("y", pos[1] + 10);
	}
});

inline function pitchLock(obj)
{
	// Repitch
	obj.frequency *= pitchFactor;

	// Apply noise gain (bandwidth is the noise amount, 1 = full noise, 0 = pure sinusoidal)
	obj.bandwidth *= noiseGain;

	// calculate the "real" harmonic
	local ratio = Math.round(obj.frequency / obj.rootFrequency);

	// calculate the fully locked frequency
	local lockedFrequency = ratio * obj.rootFrequency;

	// interpolate between the locked and original frequency
	obj.frequency = pitchLockAmount * lockedFrequency + (1.0 - pitchLockAmount) * obj.frequency;
}

