inline function create(panelId: string, switcherId: string, componentType: string)
{
	local panel = Content.getComponent(panelId);
	local children = [];

	for (x in panel.getChildComponents())
	{
		if (x.getId() == switcherId)
			continue;

		if ((componentType == "all" || x.get("type") == componentType) && x.get("parentComponent") == panelId)
			children.push(x.getId());
	}

	// Broadcaster definition
	panel.data.bc = Engine.createBroadcaster({id: panelId.replace("pnl") + "SwitcherPanel", args: ["component", "value"]});
	panel.data.bc.attachToComponentValue(switcherId, "Value");

	panel.data.bc.addComponentPropertyListener(children, "visible", "Change tab visibility", function(index, component,
	        value)
	{
		return value == index || index == -1;
	});

	return panel;
}
}

