	template <typename T> void process(T& data)
	{
		for(auto ch : data)
		{
			for(auto& s : data.toChannelData(ch))
				s = getSample(s);
		}
	}

	template <typename T> void processFrame(T& data)
	{
		for(auto& s : data)
			s = getSample(s);
	}

