inline function withAspectRatioLike(area, otherArea)
{
	local ar = otherArea[3] / otherArea[2];
	local w, h, x, y;

	if (ar > 1.0)
	{
		w = area[3] / ar;
		h = area[3];
		x = area[0] + Math.abs(w - area[2]) / 2.0;
		y = area[1];
	}

	else
	{
		w = area[2];
		h = area[2] * ar;
		x = area[0];
		y = area[1] + Math.abs(h - area[3]) / 2.0;
	}

	return [x, y, w, h];
}

