laf.registerFunction("drawRotarySlider", function(g, obj)
{
	var thickness = 4;
	var a = [obj.area[0] + thickness / 2, obj.area[1] + thickness / 2, obj.area[2] - thickness, obj.area[2] - thickness];

	if (obj.area[3] > obj.area[2])
	{
		var text;

		if (obj.text == "")
			text = obj.valueAsText;

		else
			text = obj.hover || obj.clicked ? obj.valueAsText : obj.text;

		g.setFont("Oxygen", 16);
		g.setColour(Colours.withMultipliedAlpha(obj.textColour, obj.enabled ? 1.0 : 0.5));
		g.drawAlignedText(text, obj.area, "centredBottom");
	}

	g.setColour(Colours.withMultipliedAlpha(obj.bgColour, obj.enabled ? 1.0 : 0.5));

	var innerCircleArea = [a[0] + a[2] * 0.15, a[1] + a[3] * 0.15, a[2] - a[2] * 0.3, a[3] - a[3] * 0.3];
	g.fillEllipse(innerCircleArea);

	var offset = 2.3;
	var endOffset = -offset + 2 * offset * obj.valueNormalized;
	var isBidirectional = -1.0 * obj.min == obj.max;
	var strokeStyle = {EndCapStyle: "rounded", Thickness: thickness};
	var diameter = obj.area[2] - thickness * 2;

	// Value arc
	g.setColour(obj.bgColour);

	var path = Content.createPath();

	path.addArc([0, 0, 1, 1], (-offset * !isBidirectional), offset);

	var pathArea = path.getBounds(diameter);
	pathArea[0] += obj.area[2] / 2 - diameter / 2;
	pathArea[1] += a[1] + 2;

	g.drawPath(path, pathArea, strokeStyle);

	var c = Colours.withMultipliedBrightness(obj.itemColour2, obj.hover ? 1.0 - 0.1 * obj.clicked : 0.9);
	g.setColour(Colours.withMultipliedAlpha(c, obj.enabled ? 1.0 : 0.5));
	path = Content.createPath();

	path.addArc([0, 0, 1, 1], (-offset * !isBidirectional), endOffset);

	pathArea = path.getBounds(diameter);
	pathArea[0] += obj.area[2] / 2 - diameter / 2;
	pathArea[1] += a[1] + 2;

	g.drawPath(path, pathArea, strokeStyle);

	// Value indicator
	g.rotate(endOffset, [obj.area[2] / 2, obj.area[2] / 2]);
	g.fillRoundedRectangle([a[0] + a[2] / 2 - thickness / 2, a[1] + 18, thickness, a[3] / 4], 1);
});

