const var BUF_OSC_L = BUFFER_L.getDisplayBuffer(0);
const var BUF_OSC_R = BUFFER_R.getDisplayBuffer(1);
const var pnl_Osc = Content.getComponent("pnl_Osc1");
const var timer = Engine.createTimerObject();
const var Button1 = Content.getComponent("Button1");

const BUF_LENGTH = 4096;  // Reduced buffer size for better CPU

// Set properties for both buffers (now mono since each handles one channel)
reg BUF_PROPERTIES = {"BufferLength": BUF_LENGTH, "NumChannels": 1};
BUF_OSC_L.setRingBufferProperties(BUF_PROPERTIES);
BUF_OSC_L.setActive(true);
BUF_OSC_R.setRingBufferProperties(BUF_PROPERTIES);
BUF_OSC_R.setActive(true);

// Separate buffers for left and right channels
const TEMP_BUFFER_L = Buffer.create(BUF_LENGTH);
const TEMP_BUFFER_R = Buffer.create(BUF_LENGTH);
const DRAW_BUFFER_L = Buffer.create(BUF_LENGTH);
const DRAW_BUFFER_R = Buffer.create(BUF_LENGTH);

const FRAME_COUNT = 3;
reg frameBuffersL = [];
reg frameBuffersR = [];
reg currentFrameIndex = 0;

// Cached path objects for both channels
reg mainPathL = Content.createPath();
reg mainPathR = Content.createPath();
reg trailPathL = Content.createPath();
reg trailPathR = Content.createPath();

// Initialize frame buffers for both channels
for (i = 0; i < FRAME_COUNT; i++)
{
	frameBuffersL.push(Buffer.create(BUF_LENGTH));
	frameBuffersR.push(Buffer.create(BUF_LENGTH));
}

reg magnitudeL = 0.5;
reg magnitudeR = 0.5;
const MAGNITUDE_SMOOTH = 0.9;
const MIN_MAGNITUDE = 0.05;

// Decimation
const DECIMATE_FACTOR = 32;
const DRAW_EVERY_N_FRAMES = 1;
reg frameCounter = 0;

const BACKGROUND_COLOUR = 0x00000000;
const WAVEFORM_COLOUR_L = 0xA0FFAE00;  // Left channel - greenish
const WAVEFORM_COLOUR_R = 0xA0FF4000;  // Right channel - orangish
const WAVEFORM_SHADOW_L = 0x60FF8000;
const WAVEFORM_SHADOW_R = 0x60FF2000;
const WAVEFORM_TRAIL_L = 0x30FFAE00;
const WAVEFORM_TRAIL_R = 0x30FF4000;

// Lower values for better performance
const GLOW_EFFECT = true;
const MOTION_TRAILS = true;
const CORNER_SMOOTH = 3.0;
const PATH_THICKNESS = 2.0;

// Magnitude update for both channels
inline function updateMagnitudes()
{
	local newMagL = DRAW_BUFFER_L.getMagnitude();
	local newMagR = DRAW_BUFFER_R.getMagnitude();

	magnitudeL = magnitudeL * MAGNITUDE_SMOOTH + newMagL * (1.0 - MAGNITUDE_SMOOTH);
	magnitudeR = magnitudeR * MAGNITUDE_SMOOTH + newMagR * (1.0 - MAGNITUDE_SMOOTH);

	magnitudeL = Math.max(MIN_MAGNITUDE, magnitudeL);
	magnitudeR = Math.max(MIN_MAGNITUDE, magnitudeR);
}

// Frame storage for both channels
inline function storeCurrentFrames()
{
	for (i = 0; i < BUF_LENGTH; i += DECIMATE_FACTOR)
	{
		frameBuffersL[currentFrameIndex][i] = DRAW_BUFFER_L[i];
		frameBuffersR[currentFrameIndex][i] = DRAW_BUFFER_R[i];
	}

	currentFrameIndex = (currentFrameIndex + 1) % FRAME_COUNT;
}

// Drawing function for stereo oscilloscope
inline function drawStereoOscilloscope(g, panel, magL, magR)
{
	g.fillAll(BACKGROUND_COLOUR);

	local width = panel.getWidth();
	local height = panel.getHeight();
	local quarterY = height / 4;
	local threeQuarterY = 3 * height / 4;

	// Calculate bounds for each channel (split vertically)
	local scaledHeightL = (height / 2) * Math.min(1.0, magL);
	local scaledHeightR = (height / 2) * Math.min(1.0, magR);
	local drawYL = quarterY - scaledHeightL / 2;
	local drawYR = threeQuarterY - scaledHeightR / 2;
	local boundsL = [0, drawYL, width, scaledHeightL];
	local boundsR = [0, drawYR, width, scaledHeightR];

	// Draw trail frames if enabled
	if (MOTION_TRAILS)
	{
		for (frameIdx = 0; frameIdx < FRAME_COUNT; frameIdx++)
		{
			if (frameIdx == currentFrameIndex)
				continue;

			local age = (currentFrameIndex - frameIdx + FRAME_COUNT) % FRAME_COUNT;
			local opacity = 0.7 - (age / FRAME_COUNT) * 0.6;

			// Left channel trails
			trailPathL.clear();
			local sampleL = Math.max(-1.0, Math.min(1.0, frameBuffersL[frameIdx][0]));
			trailPathL.startNewSubPath(0, quarterY - sampleL * (scaledHeightL / 2));

			for (i = DECIMATE_FACTOR; i < BUF_LENGTH; i += DECIMATE_FACTOR)
			{
				local x = (i / BUF_LENGTH) * width;
				sampleL = Math.max(-1.0, Math.min(1.0, frameBuffersL[frameIdx][i]));
				trailPathL.lineTo(x, quarterY - sampleL * (scaledHeightL / 2));
			}

			trailPathL.roundCorners(CORNER_SMOOTH);

			// Right channel trails
			trailPathR.clear();
			local sampleR = Math.max(-1.0, Math.min(1.0, frameBuffersR[frameIdx][0]));
			trailPathR.startNewSubPath(0, threeQuarterY - sampleR * (scaledHeightR / 2));

			for (i = DECIMATE_FACTOR; i < BUF_LENGTH; i += DECIMATE_FACTOR)
			{
				local x = (i / BUF_LENGTH) * width;
				sampleR = Math.max(-1.0, Math.min(1.0, frameBuffersR[frameIdx][i]));
				trailPathR.lineTo(x, threeQuarterY - sampleR * (scaledHeightR / 2));
			}

			trailPathR.roundCorners(CORNER_SMOOTH);

			// Draw trails
			g.setColour(Colours.withAlpha(WAVEFORM_TRAIL_L, opacity * 0.5));
			g.drawPath(trailPathL, boundsL, {"Thickness": PATH_THICKNESS * 0.5});

			g.setColour(Colours.withAlpha(WAVEFORM_TRAIL_R, opacity * 0.5));
			g.drawPath(trailPathR, boundsR, {"Thickness": PATH_THICKNESS * 0.5});
		}
	}

	// Draw main paths
	local currentFrameL = frameBuffersL[currentFrameIndex];
	local currentFrameR = frameBuffersR[currentFrameIndex];

	// Left channel main path
	mainPathL.clear();
	local sampleL = Math.max(-1.0, Math.min(1.0, currentFrameL[0]));
	mainPathL.startNewSubPath(0, quarterY - sampleL * (scaledHeightL / 2));

	for (i = DECIMATE_FACTOR; i < BUF_LENGTH; i += DECIMATE_FACTOR)
	{
		local x = (i / BUF_LENGTH) * width;
		sampleL = Math.max(-1.0, Math.min(1.0, currentFrameL[i]));
		mainPathL.lineTo(x, quarterY - sampleL * (scaledHeightL / 2));
	}

	mainPathL.roundCorners(CORNER_SMOOTH);

	// Right channel main path
	mainPathR.clear();
	local sampleR = Math.max(-1.0, Math.min(1.0, currentFrameR[0]));
	mainPathR.startNewSubPath(0, threeQuarterY - sampleR * (scaledHeightR / 2));

	for (i = DECIMATE_FACTOR; i < BUF_LENGTH; i += DECIMATE_FACTOR)
	{
		local x = (i / BUF_LENGTH) * width;
		sampleR = Math.max(-1.0, Math.min(1.0, currentFrameR[i]));
		mainPathR.lineTo(x, threeQuarterY - sampleR * (scaledHeightR / 2));
	}

	mainPathR.roundCorners(CORNER_SMOOTH);

	// Glow Effects
	if (GLOW_EFFECT)
	{
		g.setColour(Colours.withAlpha(WAVEFORM_SHADOW_L, Math.min(1.0, magL)));
		g.drawPath(mainPathL, boundsL, {"Thickness": PATH_THICKNESS * 2.0});

		g.setColour(Colours.withAlpha(WAVEFORM_SHADOW_R, Math.min(1.0, magR)));
		g.drawPath(mainPathR, boundsR, {"Thickness": PATH_THICKNESS * 2.0});
	}

	// Main waveforms
	g.setColour(WAVEFORM_COLOUR_L);
	g.drawPath(mainPathL, boundsL, {"Thickness": PATH_THICKNESS / 2});

	g.setColour(WAVEFORM_COLOUR_R);
	g.drawPath(mainPathR, boundsR, {"Thickness": PATH_THICKNESS / 2});
}

pnl_Osc.setPaintRoutine(function(g)
{
	drawStereoOscilloscope(g, this, magnitudeL, magnitudeR);
});

