inline function whichEllipse(areas, mouse)
{
	for (a in areas)
	{
		local obj = areas[a];

		local rx = obj[2] / 2;
		local ry = obj[3] / 2;
		local cx = obj[0] + rx;
		local cy = obj[1] + ry;

		local distance = Math.pow(mouse.x - cx, 2) / Math.pow(rx, 2) + Math.pow(mouse.y - cy, 2) / Math.pow(ry, 2);

		if (distance <= 1)
			return a;

		else
			Console.print("outside");
	}
};

