	{
		local a = areas[i].area;

		switch (areas[i].type)
		{
		case "ellipse":
			local rx = a[2] / 2;
			local ry = a[3] / 2;
			local cx = a[0] + rx;
			local cy = a[1] + ry;

			local distance = Math.pow(mouse.x - cx, 2) / Math.pow(rx, 2) + Math.pow(mouse.y - cy, 2) / Math.pow(ry, 2);

			if (distance <= 1)
				result.push(i);

			break;

		case "rectangle":
			if (mouse.x >= a[0] && mouse.x <= a[0] + a[2] && mouse.y >= a[1] && mouse.y <= a[1] + a[3])
				result.push(i);

			break;

		// Here I should have a case for "triangle", but I couldn't figure out
		// How to do it :)
		// So instead the triangles will go in default case, just like the
		// rectangles
		default:
			if (mouse.x >= a[0] && mouse.x <= a[0] + a[2] && mouse.y >= a[1] && mouse.y <= a[1] + a[3])
				result.push(i);

			break;
		}
	}

	return result;
};

