inline function scrollVP(idx)
{
	local visibleItemsFloat = ScriptPanel1.getHeight() / Viewport1.getHeight();

	// viewPositionY trucate to 0-1 so wee need a larger range to make it "stick"
	local lowY = 0 - (visibleItemsFloat / list.length); // below 0 limit
	local topY = 1 + (visibleItemsFloat / list.length); // above 1 limit

	local posY = remap(0, list.length - 1, lowY, topY, idx);

	Viewport1.set("viewPositionY", posY);
}


inline function lerp(a, b, t)
{
	return a * (1.0 - t) + b * t;
}

inline function invLerp(c, d, v)
{
	return (v - c) / (d - c);
}

inline function remap(inMin, inMax, outMin, outMax, value)
{
	local t = invLerp(inMin, inMax, value);
	return lerp(outMin, outMax, t);
}

