//	CHECK AND RETURN HOVERED COMPONENT ID & AREA	--------------------------
inline function whichComp(comps, area)
{
	local x = area[0];
	local y = area[1];

	for (a in comps)
	{
		local minX = a.area[0];
		local maxX = a.area[2] + minX;

		local minY = a.area[1];
		local maxY = a.area[3] + minY;

		if (x >= minX && x <= maxX && y >= minY && y <= maxY)
			return {"id": a.id, "area": a.area};
	}
}

