	g.setColour(0x770088AA);
	g.rotate(Math.toRadians(v.angles[v.order[1]]), [w / 2, h / 2]);
	g.fillTriangle([w * 0.135, 0, w * 0.73, h / 2], Math.PI);
	g.setColour(this.get("itemColour"));
