	g.drawAlignedText(Engine.doubleToString(v.values[v.order[1]], 2), [0, 0, w, h / 2 - 60], "centred");
	g.setColour(this.get("textColour"));
	g.setFont("Oxygen", this.get("borderSize"));
	g.drawAlignedText("Bandoneon", [0, 0, w, h / 2], "centred");
	g.applyMask(path, [0, 0, w, h], false);
