XYPadPnl.setMouseCallback(function(event)
{
	var x = event.mouseDownX;
	var y = event.mouseDownY;
	var v = this.data.value;

	if(event.drag || event.clicked)
	{
		v.x = Math.range(x + event.dragX, 0, this.getWidth());
		v.y = Math.range(y + event.dragY, 0, this.getHeight());

		v.xVal = (Math.floor((v.x) / this.getWidth() * 100) * 0.01);
		v.yVal = 1 - (Math.floor((v.y) / this.getHeight() * 100) * 0.01);

		// This is the magic command: you can call setValue() with
		// JSON objects too, so we just pass the entire object to the
		// internal value which then is subject to the default HISE restoring
		// mechanisms (initalisation, user preset loading, etc).
		// Javascript object referencing will make sure
		// it will always operate on the same object.
		this.setValue(v);

		this.changed();
	}

	if(event.drag || event.clicked)
		InfoLbl.setPosition(v.x, v.y + 20, 80, 30);

});


inline function onXYPadPnlControl(component, value)
{
	// It might get called with undefined at initialisation...
	if(isDefined(value))
	{
		// Store the object back into the data slot. Since we know that
		// this object is already referenced in the data slot it will not
		// reallocate.
		component.data.value = value;
		component.repaint();

		// Be aware that this function call is not realtime safe so if you
		// start controlling your XY-pad with a MIDI message, you might
		// cause drop outs because you're doing UI work on the audio thread
		InfoLbl.set("text", "x = " + value.xVal + "\n" + "y = " + value.yVal);
	}
};

