const var Label1 = Content.getComponent("Label1");

reg posX = Panel1.getGlobalPositionX();

reg posY = Panel1.getGlobalPositionY();

reg Q = 1;          // initialise Q to middle position
reg Qlabel = "";    // var for Q label display

Panel1.data.lastY = 0;

Panel1.setMouseCallback(function(event)
{

	// Dragging with script, because I didn't find a way to disable allowDragging property on the fly
	if (event.drag && !event.ctrlDown)
	{
		// Dragging with script, because I didn't find a way to disable allowDragging property on the fly
		Panel1.setPosition(posX + event.dragX,
		                   posY + event.dragY,
		                   10,
		                   10);

		Label1.setPosition(posX + event.dragX - 35,
		                   posY + event.dragY - 25,
		                   80,
		                   25);
	};

	// Q setting
	if (event.dragY) // && event.ctrlDown){
	{

		//Limit dragY range
		var y = Math.range(this.data.lastY + event.dragY, -100, 100);

		// ----------Ratio--------------   ----------Log scale for the 200 frame--------------
		Q = ((8 - 0.1) / Math.log10(200)) * (Math.log10(200) - (Math.log10(y + 100)));

		Q = Math.range(Q, 0.1, 8);

		this.data.lastY = y; //Store y value

		// Set EQ
		ParametriqEQ1.setAttribute(2, Q);

		// Display the rounded Q value
		Qlabel = Engine.doubleToString(Q, 1);
		Label1.set("text", "Q: " + Qlabel);
	}


	// On release, stores the panel position and display no text
	if (event.mouseUp)
	{
		posX = Panel1.getGlobalPositionX();
		posY = Panel1.getGlobalPositionY();
		Label1.set("text", "");
	}

});

