// Now we need to connect the draggable display to update the knobs on
// the scripting UI. In order to do so we'll use a broadcaster that
// we attach to all draggable parameters and update the knob values when they
// are changed.

const var COMPONENTS =
{
Attack:
	Content.getComponent("Attack"),
Hold:
	Content.getComponent("Hold"),
Decay:
	Content.getComponent("Decay"),
Sustain:
	Content.getComponent("Sustain"),
Release:
	Content.getComponent("Release"),
DecayCurve:
	Content.getComponent("DecayCurve"),
AttackCurve:
	Content.getComponent("AttackCurve"),
ReleaseCurve:
	Content.getComponent("ReleaseCurve"),
AttackLevel:
	Content.getComponent("AttackLevel")
};

// Now we build the list of parameters to pass into the broadcaster
const var PARAMETERS = [];

for(p in COMPONENTS)
	PARAMETERS.push(p);

// this is the broadcaster
const var dragBroadcaster = Engine.createBroadcaster(
{
id: "flexDragBroadcaster",
args: ["id", "parameter", "value"]
});

// attach it to the module parameters of the flex envelope
dragBroadcaster.attachToModuleParameter("FLEX", PARAMETERS, "drag handler");

// and update the component values on parameter change. We pass in the JSON
// object with the component references as this object for a extra neat syntax
dragBroadcaster.addListener(COMPONENTS, "update UI knobs", function(id, p, value)
{
	this[p].setValue(value);
});

}

