const var Knob2 = Content.getComponent("Knob2");

const var v = [75, 150, 500, 1040, 3600, 15000];


const var snapperBC = Engine.createBroadcaster(
{
"id": "Knob Snapper",
"args": ["component", "event"]
});

snapperBC.attachToComponentMouseEvents(Knob1, "All Callbacks", "Snapper Mouse Listener");


snapperBC.addListener("Snapper", "Snap knob values", function(component, event)
{
	if (event.drag)
	{
		if (snapBtn.getValue())
		{
			for (i = 0; i < v.length - 1; i++)
			{
				if (component.getValue() > v[i] && component.getValue() < v[i + 1])
				{
					// define the mid value between two snapping values
					var threshold = v[i] + (v[i + 1] - v[i]) / 2;

					if (component.getValue() <= threshold)
						Knob2.setValue(v[i]);

					else
						Knob2.setValue(v[i + 1]);

					Knob2.changed();

					break;
				}
			}
		}

		else
		{
			Knob2.setValue(component.getValue());
			Knob2.changed();
		}
	}
});


