inline function onRunTestControl(component, value)
{
	if(value)
	{
		//the user wishes to execute the test....

		//reset the results display....
		Results.set("text", "....");
		//reset the array weuse to test for duplicates
		paramArray.clear();
		//jsonFile = targetFile.loadFromXmlFile(); <--- oh how I wish this worked....
		// get teh file into a string...and split it based upon "="
		fileAsString = targetFile.loadAsString();
		fileAsArray = fileAsString.split("=");
		// now we shoud have an ugly array with params name and param values in adjacent array slots

		//Console.print(trace(fileAsArray));

		for (i = 0; i < fileAsArray.length; i++)
		{
			// move thru the array looking for the type of widget we care about...

			if(fileAsArray[i].contains("ScriptButton") || fileAsArray[i].contains("ScriptSlider"))
			{
				//Ok we found one.. so look in its "block" tosee if it uses a plugin param...

				reg j = i;

				while(!fileAsArray[j].contains("/>"))
				{
					// search this block for the plugin param name...
					if (fileAsArray[j].contains("pluginParameterName"))
					{
						// found it.,so the next array elemtn will include its name
						tempParam = fileAsArray[j + 1];
						// clean up
						tempParam = tempParam.substring(1, tempParam.lastIndexOf("\""));

						// check for duplicates...
						if (paramArray.indexOf(tempParam) != -1)
						{
							// dupe found...
							Results.set("text", Results.get("text") + "\n" + "ERROR--------DUPLICATE---:" + tempParam);
						}

						else
							paramArray.push(tempParam);

						// this is a param user - search the same block for its ID
						reg k = i;

						while(!fileAsArray[k].contains("/>"))
						{
							if (fileAsArray[k].contains(" id"))
							{
								tempID = fileAsArray[k + 1].substring(1, fileAsArray[k + 1].lastIndexOf("\""));
								break;  //got it so leave this search
							};

							k++;
						};

						// print the result..
						//Console.print("PARAM:" + tempParam + " -used by: " + tempID);
						Results.set("text", Results.get("text") + "\n" + "PARAM:" + tempParam + " - used by:" + tempID);

						break;  // got it so leave this search

					};

					j++;
				}

			}

		}
	};

};

