{
	var posX = event.x - this.getWidth() / 2.0;
	var posY = event.y - this.getHeight() / 2.0;

	var l = Math.sqrt((posX * posX) + (posY * posY));

	this.data.isValid = l < outer / 2.0 && l > inner / 2.0;
	this.repaint();
});

